cd /tmp && python3.12 - << 'EOF'
import json, subprocess

results = {}
with open("deps.txt") as f:
    lines = [l.strip() for l in f if l.strip()]

import urllib.request

for line in lines:
    parts = line.rsplit(":", 1)
    name, version = parts[0], parts[1]
    payload = json.dumps({"package": {"name": name, "ecosystem": "Maven"}, "version": version}).encode()
    req = urllib.request.Request("https://api.osv.dev/v1/query", data=payload, headers={"Content-Type": "application/json"})
    try:
        with urllib.request.urlopen(req, timeout=15) as resp:
            data = json.load(resp)
    except Exception as e:
        print(f"{line} ERROR {e}")
        continue
    vulns = data.get("vulns", [])
    if vulns:
        print(f"=== {line} : {len(vulns)} vuln(s) ===")
        for v in vulns:
            aliases = v.get("aliases", [])
            cve = next((a for a in aliases if a.startswith("CVE-")), v.get("id"))
            fixed = set()
            for aff in v.get("affected", []):
                if aff.get("package", {}).get("name") != name:
                    continue
                for r in aff.get("ranges", []):
                    for e in r.get("events", []):
                        if "fixed" in e:
                            fixed.add(e["fixed"])
            severity = v.get("database_specific", {}).get("severity", "?")
            print(f"  {cve} [{severity}] fixed_in={sorted(fixed)} :: {v.get('summary','')[:100]}")
    else:
        print(f"{line} : clean")
EOF

